26: const (
27: 	authenticationHeaderKey = "authorization"
28: 	cookieHeaderKey         = "grpcgateway-cookie"
29: )
30: 
31: type authenticationScheme uint8
32: 
33: const (
34: 	_ authenticationScheme = iota
35: 	authenticationSchemeBearer
36: 	authenticationSchemeJWT
37: )
38: 
39: func (a authenticationScheme) String() string {
40: 	switch a {
41: 	case authenticationSchemeBearer:
42: 		return "Bearer"
43: 	case authenticationSchemeJWT:
44: 		return "JWT"
45: 	default:
46: 		return ""
47: 	}
48: }
49: 
50: var ErrUnauthenticated = status.Error(codes.Unauthenticated, "request was not authenticated")
51: 
52: type authenticationContextKey struct{}
53: 
54: // ClientTokenAuthenticator is the minimum subset of an authentication provider
55: // required by the middleware to perform lookups for Authentication instances
56: // using a obtained clientToken.
57: type ClientTokenAuthenticator interface {
58: 	GetAuthenticationByClientToken(ctx context.Context, clientToken string) (*authrpc.Authentication, error)
59: }
60: 
61: // GetAuthenticationFrom is a utility for extracting an Authentication stored
62: // on a context.Context instance
63: func GetAuthenticationFrom(ctx context.Context) *authrpc.Authentication {
64: 	auth := ctx.Value(authenticationContextKey{})
65: 	if auth == nil {
66: 		return nil
67: 	}
68: 
69: 	return auth.(*authrpc.Authentication)
70: }
71: 
72: // ContextWithAuthentication returns a context with the specified authentication
73: func ContextWithAuthentication(ctx context.Context, a *authrpc.Authentication) context.Context {
74: 	return context.WithValue(ctx, authenticationContextKey{}, a)
75: }
76: 
77: // InterceptorOptions configure the basic AuthUnaryInterceptors
78: type InterceptorOptions struct {
79: 	skippedServers []any
80: }
81: 
82: func skipped(ctx context.Context, server any, o InterceptorOptions) bool {
83: 	if skipSrv, ok := server.(SkipsAuthenticationServer); ok && skipSrv.SkipsAuthentication(ctx) {
84: 		return true
85: 	}
86: 
87: 	// TODO: refactor to remove this check
88: 	for _, s := range o.skippedServers {
89: 		if s == server {
90: 			return true
91: 		}
92: 	}
93: 
94: 	return false
95: }
96: 
97: // WithServerSkipsAuthentication can be used to configure an auth unary interceptor
98: // which skips authentication when the provided server instance matches the intercepted
99: // calls parent server instance.
100: // This allows the caller to registers servers which explicitly skip authentication (e.g. OIDC).
101: func WithServerSkipsAuthentication(server any) containers.Option[InterceptorOptions] {
102: 	return func(o *InterceptorOptions) {
103: 		o.skippedServers = append(o.skippedServers, server)
104: 	}
105: }
106: 
107: // ScopedAuthenticationServer is a grpc.Server which allows for specific scoped authentication.
108: type ScopedAuthenticationServer interface {
109: 	AllowsNamespaceScopedAuthentication(ctx context.Context) bool
110: }
111: 
112: // SkipsAuthenticationServer is a grpc.Server which should always skip authentication.
113: type SkipsAuthenticationServer interface {
114: 	SkipsAuthentication(ctx context.Context) bool
115: }
116: 
117: // AuthenticationRequiredInterceptor is a grpc.UnaryServerInterceptor which requires that
118: // all requests contain an Authentication instance on the context.
119: func AuthenticationRequiredInterceptor(logger *zap.Logger, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
120: 	var opts InterceptorOptions
121: 	containers.ApplyAll(&opts, o...)
122: 
123: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
124: 		// skip auth for any preconfigured servers
125: 		if skipped(ctx, info.Server, opts) {
126: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
127: 			return handler(ctx, req)
128: 		}
129: 
130: 		auth := GetAuthenticationFrom(ctx)
131: 		if auth == nil {
132: 			logger.Error("unauthenticated", zap.String("reason", "authentication required"))
133: 			return ctx, ErrUnauthenticated
134: 		}
135: 
136: 		return handler(ctx, req)
137: 	}
138: }
