154: func JWTAuthenticationInterceptor(logger *zap.Logger, validator jwt.Validator, expected jwt.Expected, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
155: 	var opts InterceptorOptions
156: 	containers.ApplyAll(&opts, o...)
157: 
158: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
159: 		// skip auth for any preconfigured servers
160: 		if skipped(ctx, info.Server, opts) {
161: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
162: 			return handler(ctx, req)
163: 		}
164: 
165: 		md, ok := metadata.FromIncomingContext(ctx)
166: 		if !ok {
167: 			logger.Error("unauthenticated", zap.String("reason", "metadata not found on context"))
168: 			return ctx, ErrUnauthenticated
169: 		}
170: 
171: 		token, err := jwtFromMetadata(md)
172: 		if err != nil {
173: 			logger.Error("unauthenticated",
174: 				zap.String("reason", "no authorization provided"),
175: 				zap.Error(err))
176: 
177: 			return ctx, ErrUnauthenticated
178: 		}
179: 
180: 		jwtClaims, err := validator.Validate(ctx, token, expected)
181: 		if err != nil {
182: 			logger.Error("unauthenticated",
183: 				zap.String("reason", "error validating jwt"),
184: 				zap.Error(err))
185: 
186: 			if errors.Is(err, context.Canceled) {
187: 				err = status.Error(codes.Canceled, err.Error())
188: 				return ctx, err
189: 			}
190: 
191: 			if errors.Is(err, context.DeadlineExceeded) {
192: 				err = status.Error(codes.DeadlineExceeded, err.Error())
193: 				return ctx, err
194: 			}
195: 
196: 			return ctx, ErrUnauthenticated
197: 		}
198: 
199: 		metadata := map[string]string{}
200: 
201: 		userClaims, ok := jwtClaims["user"].(map[string]interface{})
202: 		if ok {
203: 			for _, fields := range [][2]string{
204: 				{"email", "email"},
205: 				{"sub", "sub"},
206: 				{"image", "picture"},
207: 				{"name", "name"},
208: 			} {
209: 				if v, ok := userClaims[fields[0]]; ok {
210: 					metadata[fmt.Sprintf("io.flipt.auth.jwt.%s", fields[1])] = fmt.Sprintf("%v", v)
211: 				}
212: 			}
213: 		}
214: 
215: 		auth := &authrpc.Authentication{
216: 			Method:   authrpc.Method_METHOD_JWT,
217: 			Metadata: metadata,
218: 		}
219: 
220: 		return handler(ContextWithAuthentication(ctx, auth), req)
221: 	}
222: }
