224: func ClientTokenInterceptorSelector() selector.Matcher {
225: 	return selector.MatchFunc(func(ctx context.Context, _ interceptors.CallMeta) bool {
226: 		md, ok := metadata.FromIncomingContext(ctx)
227: 		if !ok {
228: 			return false
229: 		}
230: 
231: 		_, err := clientTokenFromMetadata(md)
232: 		return err == nil
233: 	})
234: }
