38: func getAuthStore(
39: 	ctx context.Context,
40: 	logger *zap.Logger,
41: 	cfg *config.Config,
42: 	forceMigrate bool,
43: ) (storageauth.Store, func(context.Context) error, error) {
44: 	var (
45: 		store    storageauth.Store = storageauthmemory.NewStore()
46: 		shutdown                   = func(context.Context) error { return nil }
47: 	)
48: 
49: 	if cfg.Authentication.RequiresDatabase() {
50: 		_, builder, driver, dbShutdown, err := getDB(ctx, logger, cfg, forceMigrate)
51: 		if err != nil {
52: 			return nil, nil, err
53: 		}
54: 
55: 		store = authsql.NewStore(driver, builder, logger)
56: 		shutdown = dbShutdown
57: 
58: 		if cfg.Authentication.ShouldRunCleanup() {
59: 			var (
60: 				oplock  = oplocksql.New(logger, driver, builder)
61: 				cleanup = cleanup.NewAuthenticationService(
62: 					logger,
63: 					oplock,
64: 					store,
65: 					cfg.Authentication,
66: 				)
67: 			)
68: 
69: 			cleanup.Run(ctx)
70: 
71: 			dbShutdown := shutdown
72: 			shutdown = func(ctx context.Context) error {
73: 				logger.Info("shutting down authentication cleanup service...")
74: 
75: 				if err := cleanup.Shutdown(ctx); err != nil {
76: 					_ = dbShutdown(ctx)
77: 					return err
78: 				}
79: 
80: 				return dbShutdown(ctx)
81: 			}
82: 		}
83: 	}
84: 
85: 	return store, shutdown, nil
86: }
