88: func authenticationGRPC(
89: 	ctx context.Context,
90: 	logger *zap.Logger,
91: 	cfg *config.Config,
92: 	forceMigrate bool,
93: 	tokenDeletedEnabled bool,
94: 	authOpts ...containers.Option[authmiddlewaregrpc.InterceptorOptions],
95: ) (grpcRegisterers, []grpc.UnaryServerInterceptor, func(context.Context) error, error) {
96: 
97: 	shutdown := func(ctx context.Context) error {
98: 		return nil
99: 	}
100: 
101: 	authCfg := cfg.Authentication
102: 
103: 	// NOTE: we skip attempting to connect to any database in the situation that either the git, local, or object
104: 	// FS backends are configured.
105: 	// All that is required to establish a connection for authentication is to either make auth required
106: 	// or configure at-least one authentication method (e.g. enable token method).
107: 	if !authCfg.Enabled() && (cfg.Storage.Type != config.DatabaseStorageType) {
108: 		return grpcRegisterers{
109: 			public.NewServer(logger, authCfg),
110: 			authn.NewServer(logger, storageauthmemory.NewStore()),
111: 		}, nil, shutdown, nil
112: 	}
113: 
114: 	store, shutdown, err := getAuthStore(ctx, logger, cfg, forceMigrate)
115: 	if err != nil {
116: 		return nil, nil, nil, err
117: 	}
118: 
119: 	if cfg.Cache.Enabled {
120: 		cacher, _, err := getCache(ctx, cfg)
121: 		if err != nil {
122: 			return nil, nil, nil, err
123: 		}
124: 		store = storageauthcache.NewStore(store, cacher, logger)
125: 	}
126: 
127: 	var (
128: 		authServer   = authn.NewServer(logger, store, authn.WithAuditLoggingEnabled(tokenDeletedEnabled))
129: 		publicServer = public.NewServer(logger, authCfg)
130: 
131: 		register = grpcRegisterers{
132: 			publicServer,
