		_, err = interceptor(ctx, nil, &grpc.UnaryServerInfo{Server: &grpc.Server{}}, handler)

		// Expired token should be rejected
		assert.Error(t, err)
		assert.Equal(t, authmiddlewaregrpc.ErrUnauthenticated, err)
	})
}

