// mockServer implements the SkipsAuthenticationServer interface for testing
type mockSkippableServer struct {
	grpc.UnaryServerInterceptor
	shouldSkip bool
}

func (s *mockSkippableServer) SkipsAuthentication(ctx context.Context) bool {
	return s.shouldSkip
}

