162: 		if info.Cleanup.GracePeriod <= 0 {
163: 			return errFieldWrap(field+".cleanup.grace_period", errPositiveNonZeroDuration)
164: 		}
165: 	}
166: 
167: 	// ensure that when a session compatible authentication method has been
168: 	// enabled that the session cookie domain has been configured with a non
169: 	// empty value.
170: 	if sessionEnabled {
171: 		if c.Session.Domain == "" {
172: 			err := errFieldWrap("authentication.session.domain", errValidationRequired)
173: 			return fmt.Errorf("when session compatible auth method enabled: %w", err)
174: 		}
175: 
176: 		host, err := getHostname(c.Session.Domain)
177: 		if err != nil {
178: 			return fmt.Errorf("invalid domain: %w", err)
179: 		}
180: 
181: 		// strip scheme and port from domain
182: 		// domain cookies are not allowed to have a scheme or port
183: 		// https://github.com/golang/go/issues/28297
184: 		c.Session.Domain = host
185: 	}
186: 
187: 	for _, info := range c.Methods.AllMethods() {
188: 		if err := info.validate(); err != nil {
189: 			return err
190: 		}
191: 	}
192: 
193: 	return nil
194: }
